INSERT INTO `tb_questao` (`cod_questao`, `cod_disc`, `cod_assunto`, `descricao`, `imagem`, `item_A`, `item_B`, `item_C`, `item_D`, `item_E`, `resp_correta`) VALUES
(11, 9, 4, '<p>(Enem 2019) Na fam&iacute;lia Retroviridae encontram-se diversos v&iacute;rus que infectam aves e mam&iacute;feros, sendo caracterizada pela produ&ccedil;&atilde;o de DNA a partir de uma mol&eacute;cula de RNA. Alguns retrov&iacute;rus infectam exclusivamente humanos, n&atilde;o necessitando de outros hospedeiros, reservat&oacute;rios ou vetores biol&oacute;gicos. As infec&ccedil;&otilde;es ocasionadas por esses v&iacute;rus v&ecirc;m causando mortes e grandes preju&iacute;zos ao desenvolvimento social e econ&ocirc;mico. Nesse contexto, pesquisadores t&ecirc;m produzido medicamentos que contribuem para o tratamento dessas doen&ccedil;as.</p><p>Que avan&ccedil;os tecnol&oacute;gicos t&ecirc;m contribu&iacute;do para o tratamento dessas infec&ccedil;&otilde;es virais?</p>', '0', 'Melhoria dos métodos de controle dos vetores desses vírus.', 'Fabricação de soros mutagênicos para combate desses vírus.', 'Investimento da indústria em equipamentos de proteção individual.', 'Produção de vacinas que evitam a infecção das células hospedeiras.', 'Desenvolvimento de antirretrovirais que dificultam a reprodução desses vírus.', 'b'),
(12, 2, 1, '<p>(Enem PPL 2016) O pacote de salgadinho preferido de uma menina &eacute; vendido em embalagens com diferentes quantidades. A cada embalagem &eacute; atribu&iacute;do um n&uacute;mero de pontos na promo&ccedil;&atilde;o: &ldquo;Ao totalizar exatamente 12 pontos em embalagens e acrescentar mais R$ 10,00 ao valor da compra, voc&ecirc; ganhar&aacute; um bichinho de pel&uacute;cia&rdquo;.</p><p>Esse salgadinho &eacute; vendido em tr&ecirc;s embalagens com as seguintes massas, pontos e pre&ccedil;os:</p><p>A menor quantia a ser gasta por essa menina que a possibilite levar o bichinho de pel&uacute;cia nessa promo&ccedil;&atilde;o &eacute;</p><p>&nbsp;</p>', 'o-pacote-de-salgadinho-preferido-de-uma-menina-e.png', 'R$ 10,80.', 'R$ 12,80.', 'R$ 20,80.', 'R$ 22,00.', 'R$ 22,80.', 'c'),
(13, 2, 1, '<p>(Enem 2017) Quanto tempo voc&ecirc; fica conectado &agrave; internet? Para responder a essa pergunta foi criado um miniaplicativo de computador que roda na &aacute;rea de trabalho, para gerar automaticamente um gr&aacute;fico de setores, mapeando o tempo que uma pessoa acessa cinco sites visitados. Em um computador, foi observado que houve um aumento significativo do tempo de acesso da sexta-feira para o s&aacute;bado, nos cinco sites mais acessados. A seguir, temos os dados do miniaplicativo para esses dias.</p><p>Analisando os gr&aacute;ficos do computador, a maior taxa de aumento no tempo de acesso, da sexta-feira para o s&aacute;bado, foi no site</p>', 'quanto-tempo-voce-fica-conectado-a-internet-para-responde.png', 'x', 'y', 'z', 'w', 'u', 'd'),
(14, 2, 1, '<p>(Enem 2017) Dois reservat&oacute;rios A e B s&atilde;o alimentados por bombas distintas por um per&iacute;odo de 20 horas. A quantidade de &aacute;gua contida em cada reservat&oacute;rio nesse per&iacute;odo pode ser visualizada na figura.</p><p>O n&uacute;mero de horas em que os dois reservat&oacute;rios cont&ecirc;m a mesma quantidade de &aacute;gua &eacute;</p>', 'dois-reservatorios-a-e-b-sao-alimentados.png', '1', '2', '4', '5', '6', 'a'),
(15, 2, 1, '<p>Digite aqui a descri&ccedil;&atilde;o da quest&atilde;o</p>', '00135ffa-17f0-48be-8484-6339e0e77017.jpg', 'A', 'B', 'C', 'D', 'E', 'a'),
(16, 2, 6, '<p><strong>(Enem 2011)</strong> O n&uacute;mero mensal de passagens de uma determinada empresa a&eacute;rea aumentou no ano passado nas seguintes condi&ccedil;&otilde;es: em janeiro foram vendidas 33.000 passagens; em fevereiro, 34.500; em mar&ccedil;o, 36.000. Esse padr&atilde;o de crescimento se mant&eacute;m para os meses subsequentes. Quantas passagens foram vendidas por essa empresa em julho do ano passado?</p>', '0', '38.000', '40.500', '41.000', '42.000', '48.000', 'd'),
(17, 2, 6, '<p>(<strong>Enem 2012</strong>) Jogar baralho &eacute; uma atividade que estimula o racioc&iacute;nio. Um jogo tradicional &eacute; a Paci&ecirc;ncia, que utiliza 52 cartas. Inicialmente s&atilde;o formadas sete colunas com as cartas. A primeira coluna tem uma carta, a segunda tem duas cartas, a terceira tem tr&ecirc;s cartas, a quarta tem quatro cartas, e assim sucessivamente at&eacute; a s&eacute;tima coluna, a qual tem sete cartas, e o que sobra forma o monte, que s&atilde;o as cartas n&atilde;o utilizadas nas colunas. A quantidade de cartas que forma o monte &eacute; ?</p>', '0', '21.', '24.', '26.', '28.', '31.', 'b'),
(18, 2, 6, '<p><strong>(Enem 2018</strong>) A prefeitura de um pequeno munic&iacute;pio do interior decide colocar postes para ilumina&ccedil;&atilde;o ao longo de uma estrada retil&iacute;nea, que inicia em uma pra&ccedil;a central e termina numa fazenda na zona rural. Como a pra&ccedil;a j&aacute; possui ilumina&ccedil;&atilde;o, o primeiro poste ser&aacute; colocado a 80 metros da pra&ccedil;a, o segundo, a 100 metros, o terceiro, a 120 metros, e assim sucessivamente, mantendo-se sempre uma dist&acirc;ncia de vinte metros entre os postes, at&eacute; que o &uacute;ltimo poste seja colocado a uma dist&acirc;ncia de 1 380 metros da pra&ccedil;a.Se a prefeitura pode pagar, no m&aacute;ximo, R$ 8 000,00 por poste colocado, o maior valor que poder&aacute; gastar com a coloca&ccedil;&atilde;o desses postes &eacute; ?</p>', '0', 'R$512 000,00', 'R$520 000,00  ', 'R$528 000,00 ', 'R$552 000,00 ', 'R$584 000,00.', 'c'),
(19, 2, 6, '<p><strong>(Enem 2010)</strong> O trabalho em empresas de festas exige dos profissionais conhecimentos de diferentes &aacute;reas. Na semana passada, todos os funcion&aacute;rios de uma dessas empresas estavam envolvidos na tarefa de determinar a quantidade de estrelas que seriam utilizadas na confec&ccedil;&atilde;o de um painel de Natal.<br />Um dos funcion&aacute;rios apresentou um esbo&ccedil;o das primeiras cinco linhas do painel, que ter&aacute;, no total, 150 linhas.</p><p>Ap&oacute;s avaliar o esbo&ccedil;o, cada um dos funcion&aacute;rios esbo&ccedil;ou sua resposta:<br />FUNCION&Aacute;RIO I: aproximadamente 200 estrelas. FUNCION&Aacute;RIO II: aproximadamente 6 000 estrelas. FUNCION&Aacute;RIO III: aproximadamente 12 000 estrelas. FUNCION&Aacute;RIO IV: aproximadamente 22 500 estrelas. FUNCION&Aacute;RIO V: aproximadamente 22 800 estrelas.<br />Qual funcion&aacute;rio apresentou um resultado mais pr&oacute;ximo da quantidade de estrelas necess&aacute;ria?</p>', 'img.png', 'I', 'II', 'III', 'IV', 'V', 'c'),
(20, 2, 6, '<p><strong>(Enem 2010)</strong> Nos &uacute;ltimos anos, a corrida de rua cresce no Brasil. Nunca se falou tanto no assunto como hoje, e a quantidade de adeptos aumenta progressivamente, afinal, correr traz in&uacute;meros benef&iacute;cios para a sa&uacute;de f&iacute;sica e mental, al&eacute;m de ser um esporte que n&atilde;o exige um alto investimento financeiro.<br />Um corredor estipulou um plano de treinamento di&aacute;rio, correndo 3 quil&ocirc;metros no primeiro dia e aumentando 500 metros por dia, a partir do segundo. Contudo, seu m&eacute;dico cardiologista autorizou essa atividade at&eacute; que o corredor atingisse, no m&aacute;ximo, 10 km de corrida em um mesmo dia de treino. Se o atleta cumprir a recomenda&ccedil;&atilde;o m&eacute;dica e praticar o treinamento estipulado corretamente em dias consecutivos, pode-se afirmar que esse planejamento de treino s&oacute; poder&aacute; ser executado em, exatamente ?</p>', '0', '12 dias ', '13 dias ', '14 dias ', '15 dias ', '16 dias ', 'd'),
(21, 2, 6, '<p><strong>(Enem 2013)</strong> Para um principiante em corrida, foi estipulado o seguinte plano de treinamento di&aacute;rio: correr 300 metros no primeiro dia e aumentar 200 metros por dia, a partir do segundo. Para contabilizar seu rendimento, ele utilizar&aacute; um <em>chip</em>, preso ao seu t&ecirc;nis, para medir a dist&acirc;ncia percorrida nos treinos. Considere que esse chip armazene, em sua mem&oacute;ria, no m&aacute;ximo 9,5 km de corrida/caminhada, devendo ser colocado no momento do in&iacute;cio do treino e descartado ap&oacute;s esgotar o espa&ccedil;o para reserva de dados. Se esse atleta utilizar o <em>chip</em> desde o primeiro dia de treinamento, por quantos dias consecutivos esse <em>chip </em>poder&aacute; armazenar a quilometragem desse plano de treino di&aacute;rio ?</p>', '0', '7', '8', '9 ', '12', '13', 'b'),
(22, 2, 6, '<p><strong>(Enem 2012)</strong> Um jovem lan&ccedil;a uma bola de borracha para observar sua trajet&oacute;ria e altura h (em metros) atingida ao longo de um certo intervalo de tempo t (em segundos). Nesse intervalo, a bola quica no ch&atilde;o algumas vezes, perdendo altura progressivamente. Parte de sua trajet&oacute;ria est&aacute; descrita na figura a seguir.</p><p>Em suas observa&ccedil;&otilde;es, quantas vezes o jovem p&ocirc;de constatar que a bola atingiu a marca de 35 metros?</p>', 'img2.png', 'Nenhuma.', 'Uma vez.', 'Duas vezes.', 'Quatro vezes.', 'Cinco vezes.', 'a'),
(23, 2, 6, '<p><strong>(Enem 2012)</strong> A tabela seguinte apresenta a m&eacute;dia, em kg, de res&iacute;duos domiciliares produzidos anualmente por habitante, no per&iacute;odo de 1995 a 2005.</p><p>Se essa produ&ccedil;&atilde;o continuar aumentando, mantendo o mesmo padr&atilde;o observado na tabela, a previs&atilde;o de produ&ccedil;&atilde;o de res&iacute;duos domiciliares, por habitante no ano de 2020, em kg, ser&aacute; ?</p>', 'img3.png', '610', ' 640', '660', '700', '710', 'c'),
(24, 2, 6, '<p><strong>(Enem 2011)</strong> Atualmente existem muitos aplicativos de fazendas virtuais que, apesar de cr&iacute;ticas, possuem uma enorme quantidade de usu&aacute;rios. Embora apresentem algumas diferen&ccedil;as de funcionamento, as fazendas virtuais possuem a mesma concep&ccedil;&atilde;o: cada vez que o usu&aacute;rio cuida de sua fazenda ou da de seus amigos, ganha pontos, e, quanto mais pontos acumula, maior &eacute; seu n&iacute;vel de experi&ecirc;ncia. Em um aplicativo de fazenda virtual, o usu&aacute;rio precisa de 1 000 pontos para atingir o n&iacute;vel 1. Acumulando mais 1 200 pontos, atinge o n&iacute;vel 2; acumulando mais 1 400 pontos, atinge o n&iacute;vel 3 e assim por diante, sempre com esse padr&atilde;o. Um usu&aacute;rio que est&aacute; no n&iacute;vel 15 de experi&ecirc;ncia acumulou ?</p>', '0', '3 800 pontos.', '15 200 pontos.', '32 200 pontos.', '35 000 pontos.', '36 000 pontos.', 'e'),
(25, 2, 6, '<p><strong>(Enem 2014)</strong> Um ciclista participar&aacute; de uma competi&ccedil;&atilde;o e treinar&aacute; alguns dias da seguinte maneira: no primeiro dia, pedalar&aacute; 60 km; no segundo dia, a mesma dist&acirc;ncia do primeiro mais<em> r</em> km; no terceiro dia, a mesma dist&acirc;ncia do segundo mais <em>r</em> km; e, assim, sucessivamente, sempre pedalando a mesma dist&acirc;ncia do dia anterior mais <em>r</em> km. No &uacute;ltimo dia, ele dever&aacute; percorrer 180 km, completando o treinamento com um total de 1 560 km.<br />A dist&acirc;ncia <em>r</em> que o ciclista dever&aacute; pedalar a mais a cada dia, em km, &eacute; ?</p>', '0', ' 3', '7', '10', '13', '20', 'c'),
(26, 2, 7, '<p><strong>(Enem 2017)</strong> &Agrave;s 17 h 15 min come&ccedil;a uma forte chuva, que cai com intensidade constante. Uma piscina em forma de um paralelep&iacute;pedo ret&acirc;ngulo, que se encontrava inicialmente vazia, come&ccedil;a a acumular a &aacute;gua da chuva e, &agrave;s 18 horas, o n&iacute;vel da &aacute;gua em seu interior alcan&ccedil;a 20 cm de altura. Nesse instante, &eacute; aberto o registro que libera o escoamento da &aacute;gua por um ralo localizado no fundo dessa piscina, cuja vaz&atilde;o &eacute; constante. &Agrave;s 18 h 40 min a chuva cessa e, nesse exato instante, o n&iacute;vel da &aacute;gua na piscina baixou para 15 cm.</p><p>O instante em que a &aacute;gua dessa piscina terminar de escoar completamente est&aacute; compreendido entre</p>', '0', '19 h 30 min e 20 h 10 min.', '19 h 20 min e 19 h 30 min.', '19 h 10 min e 19 h 20 min.', '19 h e 19 h 10 min.', '18 h 40 min e 19 h. ', 'd'),
(27, 2, 7, '<p><strong>(Enem 2012)</strong> Uma m&atilde;e recorreu &agrave; bula para verificar a dosagem de um rem&eacute;dio que precisava dar a seu filho. Na bula, recomendava-se a seguinte dosagem: 5 gotas para cada 2kg de massa corporal a cada 8 horas.</p><p>Se a m&atilde;e ministrou corretamente 30 gotas do rem&eacute;dio a seu filho a cada 8 horas, ent&atilde;o a massa corporal dele &eacute; de:</p>', '0', '12 kg ', '16 kg', '24 kg', '36 kg', '75 kg', 'a'),
(28, 2, 7, '<p><strong>(Enem 2013)</strong> Uma ind&uacute;stria tem um reservat&oacute;rio de &aacute;gua com capacidade para 900 m&sup3;. Quando h&aacute; necessidade de limpeza do reservat&oacute;rio, toda a &aacute;gua precisa ser escoada. O escoamento da &aacute;gua &eacute; feito por seis ralos, e dura 6 horas quando o reservat&oacute;rio est&aacute; cheio. Esta ind&uacute;stria construir&aacute; um novo reservat&oacute;rio, com capacidade de 500 m&sup3;, cujo escoamento da &aacute;gua dever&aacute; ser realizado em 4 horas, quando o reservat&oacute;rio estiver cheio. Os ralos utilizados no novo reservat&oacute;rio dever&atilde;o ser id&ecirc;nticos aos do j&aacute; existente.</p><p>A quantidade de ralos do novo reservat&oacute;rio dever&aacute; ser igual a ?</p>', '0', '2', '4', '5', '8', '9', 'c'),
(29, 2, 7, '<p><strong>(Enem 2014)</strong> Uma ponte precisa ser dimensionada de forma que possa ter tr&ecirc;s pontos de sustenta&ccedil;&atilde;o. Sabe-se que a carga m&aacute;xima suportada pela ponte ser&aacute; de 12 t. O ponto de sustenta&ccedil;&atilde;o central receber&aacute; 60% da carga da ponte, e o restante da carga ser&aacute; distribu&iacute;do igualmente entre os outros dois pontos de sustenta&ccedil;&atilde;o.</p>', '0', '8.255.', '4.445.', '6.985.', '9.543.', '7.366.', 'c'),
(30, 2, 7, '<p><strong>(Enem 2014)</strong> Os vidros para ve&iacute;culos produzidos por certo fabricante t&ecirc;m transpar&ecirc;ncias entre 70% e 90%, dependendo do lote fabricado. Isso significa que, quando um feixe luminoso incide no vidro, uma parte entre 70% e 90% da luz consegue atravess&aacute;-lo. Os ve&iacute;culos equipados com vidros desse fabricante ter&atilde;o instaladas, nos vidros das portas, pel&iacute;culas protetoras cuja transpar&ecirc;ncia, dependendo do lote fabricado, estar&aacute; entre 50% e 70%. Considere que uma porcentagem P da intensidade da luz, proveniente de uma fonte externa, atravessa o vidro e a pel&iacute;cula.</p><p>De acordo com as informa&ccedil;&otilde;es, o intervalo das porcentagens que representam a varia&ccedil;&atilde;o total poss&iacute;vel de P &eacute;:</p>', '0', '[35;63].', '[40;63].', '[50;70].', '[50;90].', '[70;90].', 'a'),
(31, 2, 7, '<p><strong>(Enem 2011)</strong> Voc&ecirc; pode adaptar as atividades do seu dia a dia de uma forma que possa queimar mais calorias do que as gastas normalmente, conforme a rela&ccedil;&atilde;o seguinte:<br />&ndash; Enquanto voc&ecirc; fala ao telefone, fa&ccedil;a agachamentos: 100 calorias gastas em 20 minutos.<br />&ndash; Meia hora de supermercado: 100 calorias.<br />&ndash; Cuidar do jardim por 30 minutos: 200 calorias.<br />&ndash; Passear com o cachorro: 200 calorias em 30 minutos.<br />&ndash; Tirar o p&oacute; dos m&oacute;veis: 150 calorias em 30 minutos.<br />&ndash; Lavar roupas por 30 minutos: 200 calorias.</p><p><em>Uma pessoa deseja executar essas ativida</em>des, por&eacute;m, ajustando o tempo para que, em cada uma, gaste igualmente 200 calorias.<br />A partir dos ajustes, quanto tempo a mais ser&aacute; necess&aacute;rio para realizar todas as atividades?</p>', '0', '50 minutos.', '60 minutos.', '80 minutos.', '120 minutos.', '170 minutos. ', 'b'),
(32, 2, 7, '<p><strong>(ENEM 2013)</strong> Para aumentar as vendas no in&iacute;cio do ano, uma loja de departamentos remarcou os pre&ccedil;os de seus produtos 20% abaixo do pre&ccedil;o original. Quando chegam ao caixa, os clientes que possuem o cart&atilde;o fidelidade da loja t&ecirc;m direito a um desconto adicional de 10% sobre o valor total de suas compras</p><p>Um cliente deseja comprar um produto que custava R$50,00 antes da remarca&ccedil;&atilde;o de pre&ccedil;os. Ele n&atilde;o possui o cart&atilde;o fidelidade da loja. Caso esse cliente possu&iacute;sse o cart&atilde;o fidelidade da loja, a economia adicional que obteria ao efetuar a compra, em reais, seria de ?</p>', '0', '15,00', '14,00', '10,00', '5,00', '4,00', 'e'),
(33, 2, 7, '<p><strong>(Enem 2015)</strong> Segundo dados apurados no Censo 2010, para uma popula&ccedil;&atilde;o de 101,8 milh&otilde;es de brasileiros com 10 anos ou mais de idade e que teve algum tipo de rendimento em 2010, a renda m&eacute;dia mensal apurada foi de R$1202,00. A soma dos rendimentos mensais dos 10% mais pobres correspondeu a apenas 1,1% do total de rendimentos dessa popula&ccedil;&atilde;o considerada, enquanto que a soma dos rendimentos mensais dos 10% mais ricos correspondeu a 44,5% desse total.</p><p>Qual foi a diferen&ccedil;a, em reais, entre a renda m&eacute;dia mensal de um brasileiro que estava na faixa dos 10% mais ricos e de um brasileiro que estava na faixa dos 10% mais pobres?</p>', '0', '240,40', '548,11', '1 723,67', '4 026,70', '5 216,68 ', 'e'),
(34, 2, 7, '<p><strong>(Enem 2016)</strong> Em uma empresa de m&oacute;veis, um cliente encomenda um guarda-roupa nas dimens&otilde;es 220 cm de altura, 120 cm de largura e 50 cm de profundidade. Alguns dias depois, o projetista, com o desenho elaborado na escala 1 : 8, entra em contato com o cliente para fazer sua apresenta&ccedil;&atilde;o. No momento da impress&atilde;o, o profissional percebe que o desenho n&atilde;o caberia na folha de papel que costumava usar. Para resolver o problema, configurou a impressora para que a figura fosse reduzida em 20%.</p><p>A altura, a largura e a profundidade do desenho impresso para a apresenta&ccedil;&atilde;o ser&atilde;o, respectivamente,</p>', '0', '22,00 cm, 12,00 cm e 5,00 cm.', '27,50 cm, 15,00 cm e 6,25 cm. ', '34,37 cm, 18,75 cm e 7,81 cm.', '35,20 cm, 19,20 cm e 8,00 cm.', '44,00 cm, 24,00 cm e 10,00 cm. ', 'a'),
(35, 2, 7, '<p><strong>(Enem 2016)</strong> O setor de recursos humanos de uma empresa pretende fazer contrata&ccedil;&otilde;es para adequar-se ao artigo 93 da Lei n&deg; 8.213/91, que disp&otilde;e:</p><p>Art. 93. A empresa com 100 (cem) ou mais empregados est&aacute; obrigada a preencher de 2% (dois por cento) a 5% (cinco por cento) dos seus cargos com benefici&aacute;rios reabilitados ou pessoas com defici&ecirc;ncia, habilitados, na seguinte propor&ccedil;&atilde;o:</p><p><em>I. at&eacute; 200 empregados&hellip;&hellip;&hellip;&hellip;&hellip;&hellip;.. 2%;</em><br /><em>II. de 201 a 500 empregados&hellip;&hellip;&hellip;&hellip;&hellip; 3%;</em><br /><em>III. de 501 a 1 000 empregados&hellip;&hellip;&hellip;&hellip; 4%;</em><br /><em>IV. de 1 001 em diante&hellip;&hellip;&hellip;&hellip;&hellip;&hellip;. 5%</em> .</p><p>Constatou-se que a empresa possui 1 200 funcion&aacute;rios, dos quais 10 s&atilde;o reabilitados ou com defici&ecirc;ncia, habilitados.</p><p>Para adequar-se &agrave; referida lei, a empresa contratar&aacute; apenas empregados que atendem ao perfil indicado no artigo 93.</p><p>O n&uacute;mero m&iacute;nimo de empregados reabilitados ou com defici&ecirc;ncia, habilitados, que dever&aacute; ser contratado pela empresa &eacute;</p>', '0', '74', '70', '64', '60', '53', 'e'),
(36, 7, 8, '<p>1(FUVEST-SP) Para separar da melhor maneira poss&iacute;vel os tr&ecirc;s componentes de uma mistura de areia com solu&ccedil;&atilde;o aquosa de sal, devemos:</p><p>&nbsp;</p><p>&nbsp;</p>', '0', 'Filtrar e destilar.', 'Destilar e filtrar.', 'Decantar e filtrar.', 'Filtrar e decantar', 'Destilar e decantar.', 'a'),
(37, 7, 8, '<p>2(UNIP-SP O Sistema constitu&iacute;do por &aacute;gua liquida , ferro s&oacute;lido , gelo e vapor d&#39;&aacute;gua apresenta:</p>', '0', '3 fases e 3 componentes.', '4 fases e 3 componentes.', '4 fases e 2 componentes.', '4 componentes e 6 fases.', '2 fases e 2 componentes.', 'c'),
(38, 7, 8, '<p>3(FEI-SP) Submetendo-se a areia aur&iacute;fera a uma corrente de &aacute;gua , os gr&atilde;os de areia, bem mais leves, s&atilde;o arrastados , separando- se dos gr&atilde;os de ouro. Esse m&eacute;todo de separa&ccedil;&atilde;o &eacute; denominado:</p>', '0', 'Flotação.', 'Levigação', 'Decantação.', 'Catação.', 'Tamização', 'b'),
(39, 7, 8, '<p>(UNESP) Tintura de iodo &eacute; uma solu&ccedil;&atilde;o de 12 e Kl. Deixou - se um frasco desssa solu&ccedil;&atilde;o aberto e depois de certo tempo observou- se que restavam no fundo gr&atilde;os de cores violeta e branca.</p><p>Pode - se concluir, a partir desses dados, que:</p>', '0', 'A mistura original era heterogênea.', 'Ocorreu cristalização da solução.', 'Ocorreu sublimação dos componentes.', 'Ocorreu vaporização do soluto.', 'Ocorreu vaporização do solvente, restando cristais de iodo e de iodedo de potássio.', 'e'),
(40, 7, 8, '<p>(UFRG) Na obten&ccedil;&atilde;o do sal de cozinha a partir da &aacute;gua do mar, al&eacute;m de outras etapas, realiza-se:</p>', '0', 'Sifonização e filtração .', 'Cristalização e fusão fracionada.', 'Decantação e destilação fracionada.', 'Catação e centrifugação.', 'Evaporação e cristalização', 'e'),
(41, 7, 9, '<p>(ENEM-2008) As afirmativas abaixo empregam conceitos de &aacute;tomos , &iacute;ons , c&aacute;tions , e &acirc;nions.</p><p>Qual a afirmativa &eacute; a CORRETA?</p>', '0', 'O íon Na torna-se um cátion quando perde um elétron.', 'O cátion Cl- torna um íon com a perda de um elétron.', 'O átomo Cl torna-se um ânion quando ganha um elétron.', 'O ânion Na+ torna-se um cátion quando perde um elétron.', 'O átomo de Na torna- se um ânion quando ganha um elétron.', 'c'),
(42, 7, 9, '<p>(F.M. CATANDUVA-SP) Admitindo- se o &aacute;tomo esf&eacute;rico com di&acirc;metro de 10^-8 cm e a possibilidade de se &quot; esfileirar&quot; &aacute;tomos um a um , a quantidade de &aacute;tomos enfileirados suficiente para cobrir a dist&acirc;ncia da terra &agrave; lua( da ordem de 400000km) seria de, aproximadamente:</p><p>Observa&ccedil;&atilde;o: Considere 1 mol = 6,0*10^23 &aacute;tomos</p>', '0', '1 mol', '6,6 mols', '66,6 mols', '6,6*10^-6 mol', '6,6*10^6 mols', 'd'),
